import { KnowledgeBase } from 'mastra';
import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ projectId: 'your-project-id' });

const kb = new KnowledgeBase({
  retrieve: async (query) => {
    const docs = await vectorSearch(query);

    // Vex staleness detection
    const now = Date.now();
    const staleDocs = docs.filter(doc => now - doc.timestamp > 24 * 60 * 60 * 1000);

    if (staleDocs.length > 0) {
      await vex.incident({
        name: 'stale-memory-retrieval',
        severity: 'warning',
        payload: { query, staleCount: staleDocs.length, totalCount: docs.length }
      });
    }

    await vex.checkpoint({
      name: 'memory-retrieval',
      payload: { docs: docs.map(d => ({ content: d.content, age: now - d.timestamp })) },
      assertions: [{ path: 'docs[*].age', max: 7 * 24 * 60 * 60 * 1000 }]
    });

    return docs;
  }
});

