import { Tool } from 'mastra';
import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ projectId: 'your-project-id' });

function createResilientTool(toolFn: Function, schema: any) {
  return new Tool({
    name: toolFn.name,
    execute: async (params, attempt = 1) => {
      try {
        const result = await toolFn(params);
        return vex.validateSchema(result, schema) ? result : null;
      } catch (error) {
        if (attempt < 3) {
          await vex.retry({ tool: toolFn.name, attempt });
          return createResilientTool(toolFn, schema).execute(params, attempt + 1);
        }
        throw error;
      }
    }
  });
}

const safeGithubTool = createResilientTool(
  fetchGithubIssues,
  { issues: { type: 'array' } }
);

import { KnowledgeBase } from 'mastra';
import { Vex } from '@vex_dev/sdk';

const MAX_AGE_MS = 24 * 60 * 60 * 1000;

const freshKB = new KnowledgeBase({
  retrieve: async (query) => {
    const allDocs = await vectorSearch(query);
    const now = Date.now();

    // Vex-powered freshness filter
    const freshDocs = allDocs.filter(doc => 
      now - (doc.timestamp || 0) <= MAX_AGE_MS
    );

    if (freshDocs.length === 0) {
      await vex.fallback({
        name: 'no-fresh-context',
        query,
        fallback: 'Using general knowledge for this query'
      });
    }

    await vex.metric('context-freshness', {
      fresh: freshDocs.length,
      stale: allDocs.length - freshDocs.length,
      ratio: freshDocs.length / allDocs.length
    });

    return freshDocs;
  }
});

